#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int points[N][3];
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d", &points[i][0], &points[i][1], &points[i][2]);
        }
        for (int i = 0; i < Q; i++) {
            int A, B, C, D;
            scanf("%d %d %d %d", &A, &B, &C, &D);
            double sum = 0;
            for (int j = 0; j < N; j++) {
                sum += A * points[j][0] + B * points[j][1] + C * points[j][2] + D;
            }
            printf("%.6f\n", sum);
        }
    }
    return 0;
}

