import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[][] points = new int[N][3];
            for (int i = 0; i < N; i++) {
                points[i][0] = sc.nextInt();
                points[i][1] = sc.nextInt();
                points[i][2] = sc.nextInt();
            }
            for (int i = 0; i < Q; i++) {
                int A = sc.nextInt();
                int B = sc.nextInt();
                int C = sc.nextInt();
                int D = sc.nextInt();
                double sum = 0;
                for (int j = 0; j < N; j++) {
                    sum += A * points[j][0] + B * points[j][1] + C * points[j][2] + D;
                }
                System.out.printf("%.6f\n", sum);
            }
        }
    }
}

